sys_ui_action.script:
function moveToReview() {
    if (g_form.getValue('u_patch_execution')) {
        var answer = confirm("Please review the Patching Result for each CI in the Patch Execution CIs related list.\n If you click OK, all CIs without Patching Result will be automatically established as Successful. \n If some CI has had a not resolved issue and patches couldn't be installed, please click Cancel to manually modify the Patching Result to Failed directly on the list. \nNOTE: For each CI with Failed result, a Trouble will be automatically created, once you move the change to Review state.");
        if (answer) {
            g_form.setMandatory('close_code', true);
            g_form.setMandatory('close_notes', true);
            // g_form.setMandatory('u_5_expedited_changes_justification', true);
            gsftSubmit(null, g_form.getFormElement(), "state_model_move_to_review");
        } else {
            return false;
        }
    }
    var ga = new GlideAjax("ChangeRequestStateHandlerAjax");
    ga.addParam("sysparm_name", "getStateValue");
    ga.addParam("sysparm_state_name", "review");
    ga.getXMLAnswer(function(stateValue) {
        g_form.setMandatory('close_code', true);
        g_form.setMandatory('close_notes', true);
        g_form.setMandatory('u_verification_output', true);

        if (g_form.getValue('u_expedited') == 'true') {
            g_form.setMandatory('u_5_expedited_changes_justification', true);
        }
        if (g_scratchpad.delayedStartTime == true) {
            g_form.setMandatory('u_implementation_start_delayed_justification', true);
        }
        if (g_scratchpad.delayedEndTime == true) {
            g_form.setMandatory('u_implementation_end_delayed_justification', true);
        }
        g_form.setMandatory('u_second_question_review', true);

        gsftSubmit(null, g_form.getFormElement(), "state_model_move_to_review");
    });
}

// function confirmAction() {


// }
if (typeof window == 'undefined')
    setRedirect();

function setRedirect() {
    var answer = false;
    var taskGroup = false;
    var isImplementer = false;

    //	if(current.u_operating_unit == "CA"){ // For canada if the user do not belong to assnmt grp of CTask, still he/she can move the task to review state.   // commented code as per story - 2269

    var userCMgroup = new CMOwnerUsers().checkLoggedinUserBelongsToCMGroup(current.u_operating_country); // changes made as per story - 2269
    //User in CHG Implementer field;
    var implementer = [];
    implementer = current.u_person_s_who_wil_implement_the_change.split(',');
    if (implementer.length == 1) {
        if (gs.getUserID() == current.u_person_s_who_wil_implement_the_change) {
            isImplementer = true;
        }
    } else if (implementer.length > 1) {
        for (var i = 0; i < implementer.length; i++) {
            if (gs.getUserID() == implementer[i]) {
                isImplementer = true;
            }
        }
    }

    //User in assignment group from Change Task
    var gr = new GlideRecord('change_task');
    gr.addQuery('change_request', current.sys_id);
    gr.query();
    count = gr.getRowCount();
    while (gr.next()) {
        if (gs.getUser().isMemberOf(gr.assignment_group.getDisplayValue())) {
            taskGroup = true;
            break;
        }
    }
    if (gs.getUser().isMemberOf(current.assignment_group.getDisplayValue()) || gs.getUserID() == current.assigned_to || userCMgroup == true || isImplementer == true || taskGroup == true) {
        answer = true;
    }

    if (answer) {
        current.state = 0;
        current.update();
        action.setRedirectURL(current);
    } else {
        gs.addInfoMessage(gs.getMessage('EQIX Review Button'));
        action.setRedirectURL(current);
    }

}
